#!/usr/bin/env python3
"""DGX DEPLOY v19.34.246 — chart-cache RTH freshness ceiling (fixes frozen live charts).
CHART_CACHE_TTL_INTRADAY_S=28800 (8h) froze the main chart for the whole session.
Now during 04:00-20:00 ET the intraday TTL is capped to CHART_CACHE_RTH_MAX_S (default 60s);
the long TTL still applies overnight for instant revisits. Idempotent: rewrite, pytest, commit, push, restart."""
import base64, gzip, os, subprocess, sys
FILES = {
    'backend/services/chart_response_cache.py': '',
    'backend/tests/test_v19_34_246_chart_cache_rth.py': '',
}
REPO=os.getcwd()
def main():
    if not os.path.isdir(os.path.join(REPO,"backend","services")):
        print("[FATAL] not repo root"); sys.exit(1)
    for rel,b in FILES.items():
        dst=os.path.join(REPO,rel); os.makedirs(os.path.dirname(dst),exist_ok=True)
        data=gzip.decompress(base64.b64decode(b)); open(dst,"wb").write(data)
        print(f"[WROTE] {rel} ({len(data)} bytes)")
    print("[TEST] pytest v246 ...")
    r=subprocess.run([sys.executable,"-m","pytest","backend/tests/test_v19_34_246_chart_cache_rth.py","-q"],cwd=REPO)
    if r.returncode!=0: print("[FATAL] pytest failed — aborting."); sys.exit(2)
    subprocess.run(["git","add"]+list(FILES.keys()),cwd=REPO)
    c=subprocess.run(["git","commit","-m","v19.34.246 — chart-cache RTH freshness ceiling (fix frozen live charts)"],cwd=REPO)
    if c.returncode!=0: print("[INFO] commit no-op")
    p=subprocess.run(["git","push"],cwd=REPO)
    if p.returncode!=0: print("[WARN] push failed — commit is local")
    print("[RESTART] ./start_backend.sh --force"); subprocess.run(["./start_backend.sh","--force"],cwd=REPO)
    print("[DONE] v19.34.246 deployed. Intraday charts refresh <=60s during RTH.")
if __name__=="__main__": main()
